def _guard_order(profile: str) -> list[str]:
    if profile not in _VALID_PROFILES:
        raise ValueError(''.join(['unknown c0f1 dispatcher profile: ', format(profile, '')]))
    return [*(str(entry['shape_key']) for entry in _profile_entries(profile)), *baseline._guard_order(baseline.PROFILE_ALL)]

def _baseline_info(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    info = dict(baseline.route_info(inputs))
    route = str(info.get('selected_route') or info.get('route') or baseline.selected_route(inputs))
    info['profile'] = profile
    info['route'] = route
    info['selected_route'] = route
    info['guard_order'] = _guard_order(profile)
    info.setdefault('production_policy', 'weave_only')
    info.setdefault('external_fallback', None)
    info.setdefault('coverage_only', False)
    info.setdefault('missing_weave_route', False)
    if info.get('classification') == 'seed-produced':
        info['classification'] = 'seed-consumed'
    return info

def _entry_info(inputs: dict[str, Any], profile: str, entry: dict[str, Any], source_info: dict[str, Any] | None) -> dict[str, Any]:
    parent_info = dict(baseline.route_info(inputs))
    parent_route = str(parent_info.get('selected_route') or parent_info.get('route') or baseline.selected_route(inputs))
